 2	
 3	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 4	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Popover, PopoverPosition, Stack } from '@patternfly/react-core';
 7	import { HelpIcon } from '@patternfly/react-icons';
 8	
 9	const PreviewFeaturesPopover: FC = () => {
10	  const { t } = useKubevirtTranslation();
11	  return (
12	    <Popover
13	      bodyContent={
14	        <Stack hasGutter>
15	          <p>
16	            <ExternalLink href={documentationURL.DEV_PREVIEW} text={t('Developer Preview')} />
17	          </p>
18	          <p>
19	            <ExternalLink href={documentationURL.TECH_PREVIEW} text={t('Technology Preview')} />
20	          </p>
21	        </Stack>
22	      }
23	      className="preview-features-popover"
24	      headerContent={<>{t('Preview features')}</>}
25	      maxWidth="550px"
26	      position={PopoverPosition.right}
27	    >
28	      <HelpIcon className="preview-features-popover__icon" />
29	    </Popover>
30	  );
31	};
32	
33	export default PreviewFeaturesPopover;

